local LxBattleCtrl = classX("LxBattleCtrl", LxBaseCtrl)

function LxBattleCtrl:Initialize()
    LxBaseCtrl.Initialize(self)

    self._isNeedSaveFormation = false

    ----@type LBattleMgr
    self._battleMgr = require("LApp.gameplay.battleX.LBattleMgr"):new()
    self._battleMgr:Initialize()

    self._isLoginAfter = false

    self._curUIMode = BattleViewMode.None
end

function LxBattleCtrl:Dispose()
    if self._battleMgr then
        self._battleMgr:Dispose()
        self._battleMgr = nil
    end
    if self._jsonAsset then
        self._jsonAsset:Dispose()
        self._jsonAsset = nil
    end

    LxBaseCtrl.Dispose(self)
end

function LxBattleCtrl:InitAfterLoginGame()
    self._isLoginAfter = true

    self:InitAfterLoginGameEvents()
    self._isInitAfterLoginGame = true
end

function LxBattleCtrl:InitAfterLoginGameEvents()
    if self._isInitAfterLoginGame then return end
    self:AddEventHandler(EventNames.BATTLE_SHOW_END, self.OnBattleEnd, self)
    self:AddEventHandler(EventNames.LEVEL_LOAD_OK, self.OnLevelLoadOk, self)
    self:AddEventHandler(EventNames.APPLICATION_SCREEN_SIZE_CHANGE, self.OnScreenSizeChange, self)
    self:AddEventHandler(EventNames.NET_RECONNECTED, self.OnNetReConnected, self)
end

function LxBattleCtrl:OnScreenSizeChange()
