---@param reportData LFightReportData
function LxBattleCtrl:OnBattleEnd(reportData, config)
    if not self._battleMgr:HasAnyLiveBattle() then
        ClosePanel(UiNames.BattleBubble)
    end

    local reportId = ''
    if reportData then
        reportId = reportData.id
    end

    local list = CtrlCenter.Battle:GetCombatSpeedList()
    if list and #list > 0 then
        local ref = list[1]
        self._battleMgr:SetTimeScale(ref.column)
    end

    if config and config.battleType >= BattleType.Video then
        if self._battleMgr:IsBattleShow(reportId) then
            local battleConfig = {
                isRemove = true,
                reportId = reportData.id,
                battleType = config.battleType,
                report = reportData,
                uiDataForExitBattle = config.uiDataForExitBattle
            }
            self:LeaveBattle(battleConfig)
        end
        return
    end

    local battleProcess = self._battleMgr:GetBattleProcess(config.battleType)
    if battleProcess then
        battleProcess:StepBattleResultRequest()
    end
end

---移除战斗展示，当前战斗改成后台战斗
function LxBattleCtrl:RemoveShowBattle()
    if self._battleMgr then
        self._battleMgr:ChangeShowBattleToBackground()
        self._battleMgr:RemoveBattleView()
    end
end

--- { isRemove:bool, reportId:string, battleType:BattleType, isFormation:bool,report:LFightReportData }
---@param data V_Battle_BattleConfig 可能是战报或者自拟数据table
function LxBattleCtrl:LeaveBattle(data)
    local curBattleType
    if data then
        local isRemove = data.isRemove
        local reportId = data.reportId or ""
        local battleType = data.battleType
        curBattleType = battleType
        local isFormation = data.isFormation
        local report = data.report
        data.isWin = report and report.winner == 1
        if not isRemove then
            isRemove = (battleType and battleType >= BattleType.Video)
        end
        if isFormation then
            self._battleMgr:RemoveBattleView()
        elseif isRemove then
            self._battleMgr:RemoveBattle(reportId, battleType)
        else
            self._battleMgr:RemoveBattleView(reportId)
        end
    else
        self._battleMgr:RemoveBattleView()
    end

    if MgrCenter.LevelMgr:IsInLevel(LevelNames.Battle) then
        self._curUIMode = BattleViewMode.None
        local backFormation = data and data.backFormation
        ClosePanel(UiNames.Battle)
        ClosePanel(UiNames.BattleStatistics)
        ClosePanel(UiNames.BattleGain)
        if backFormation then
            ClosePanel(UiNames.BattleResult)
            if data.isNextBattle then
                if curBattleType == BattleType.Adventure then
                    CtrlCenter.FightIdle:GoToChallenge(not self._battleMgr:IsShowBattleNextInFront(curBattleType))
                    return
                end
            end

            local newData
            if data.showMode == BattleViewMode.Formation then
                newData = {
                    mapName = "Battle003",
                    showMode = BattleViewMode.Formation,
                    battleType = BattleType.Adventure,
                    modeFormationAll = true,
                    index = 1,
                    uiDataForExitBattle = { { name = UiNames.HeroMain } },
                    mainParams = {
                        botFuncType = 4,
                    }
                }
            else
                newData = {
                    backLevelName = data.backLevelName,
                    backMapName = data.backMapName,
                    battleType = data.battleType,
                    isTestBattle = data.isTestBattle,
                    index = data.index,
                    defend = data.defend,
                    targetId = data.targetId,
                    formation2 = data.formation2,
                }
                newData.backFormation = false
            end
            self:GotoFormation(newData)
        else
            self:LevelBattleFunc(data)
        end
    else
        ClosePanel(UiNames.BattleResult)

        if curBattleType == BattleType.Adventure then
            if data and data.isNextBattle then
                CtrlCenter.FightIdle:GoToChallenge(data.isFromResult)
                return
            end
        end
    end
end

