function LxBattleCtrl:LevelBattleFunc(data)
    -- 离开战斗默认进入主界面
    local config = {}
    config.mapName = data and data.backMapName or "City001"
    config.mainParams = data and data.mainParams
    config.uiDataForExitBattle = data and data.uiDataForExitBattle
    config.jumpOrigin = data and data.jumpOrigin

    local loadParams = self:GetLoadParams(not data.showMode or data.showMode == BattleViewMode.Battle)

    local levelName = data and data.backLevelName or LevelNames.Main
    if levelName == LevelNames.Main then
        CtrlCenter.Main:GoHome(config, loadParams)
    elseif levelName == LevelNames.FightIdle then
        CtrlCenter.FightIdle:ChangeFightIdleMap(loadParams)
    else
        MgrCenter.LevelMgr:LoadLevel(levelName, config, loadParams)
    end
end

