function LxBattleCtrl:GotoReplay(config)
    config = config or {}
    config.isReplay = true

    local reportId = config.reportId
    local battleLogic = self._battleMgr:GetBattleLogic(reportId)
    if not battleLogic or not battleLogic:HasReport() then
        return
    end
    if MgrCenter.LevelMgr:IsInLevel(LevelNames.Battle) then
        MgrCenter.PanelMgr:CloseAllPanelWithExcept()
        ShowPanel(UiNames.Battle, {battleConfig = config})
        self._battleMgr:ReplayBattle(reportId, true)
    else
        self._battleMgr:ResetBattle(reportId)
        config.isFormation = false
        self:GotoBattle(config)
    end
end

