--- 前往战斗场景
---@param config V_Battle_BattleConfig
function LxBattleCtrl:GotoBattle(config)

    config.mapName = config.mapName or "Battle003"
    local combatTypeConfig = GameTable.CombatTypeRef[config.battleType or 0]
    if(combatTypeConfig ~= nil)then
        local combatSceneConfig = GameTable.BattleSceneRef[combatTypeConfig.fightScene]
        if(combatSceneConfig ~= nil)then
            config.mapName = combatSceneConfig.name
        end
    end
    local battleType = config.battleType or 0

    local isBattleMode = not config.showMode or config.showMode == BattleViewMode.Battle
    local battleProcess
    local isHaveBattle = false
    local isInBattleLevel =  MgrCenter.LevelMgr:IsInLevel(LevelNames.Battle)
    local isEditChangeLevel = false

    if isBattleMode then
        self:RemoveBattleNotice(battleType, true)
        battleProcess = self._battleMgr:GetBattleProcess(battleType)
        if battleProcess then
            isHaveBattle = not battleProcess:IsDisposed() and not battleProcess:IsCanReplace()
            if isHaveBattle then
                local battle = self._battleMgr:GetLiveBattle(battleType)
                ---正在播放的战斗暂停
                if battle then battle:SetProtectOnToFront() end
            end
        end
    else
        if isInBattleLevel then
            local battleView = self._battleMgr:GetBattleView()
            isEditChangeLevel = battleView and not battleView:IsFormationEdit()
        end
    end

    if isInBattleLevel then
        if isHaveBattle then
            local battleConfig = battleProcess.battleConfig
            battleProcess.battleConfig.isOpenWithoutView = false
            local isBackBattle = false
            -- 如果当前有该类型战斗，播放之前的战斗
            if self._battleMgr:ShowLiveBattle(battleConfig.battleType) then
                ---有战报正在播放中， 直接回到战斗
                self._battleMgr:ReadyBattleView()
                isBackBattle = true
            else
                ---还没有获得战报，等战报流程进行
                ---无法还原阵形，因此不展示当前小人了，等待战报返回之后才进行
            end
            self._battleMgr:SetCameraMode(BattleCameraMode.Battle)
            ClosePanel(UiNames.Formation)
            ShowPanel(UiNames.Battle, {battleConfig = battleConfig, isBackBattle = isBackBattle})
            ShowPanel(UiNames.MainBottom)
            return
        end

        if not isEditChangeLevel then
            if config.isFormation then
                self:OpenFormation(config)
            else
                self:OpenBattle(config)
            end
            return
        end
    end
    local loadParams = self:GetLoadParams(isBattleMode)
    MgrCenter.LevelMgr:LoadLevel(LevelNames.Battle, config, loadParams)
end

--打开布阵
---@param config V_Battle_BattleConfig
function LxBattleCtrl:OpenFormation(config)
    self._curUIMode = BattleViewMode.Formation
    local battleType = config.battleType or BattleType.Adventure

    local index = config.index
    ---@type LxFormationObj
    local formation1 = config.formation1
    formation1 = formation1 or ModuleCenter.Battle:GetFormation(battleType, index, config.defend)
    if formation1 then
        local formation2 = config.formation2
        if config.isTestBattle then
            formation2 = ModuleCenter.Battle:GetFormation(battleType, 1, true)
            config.formation2 = formation2
            config.formation1 = formation1
        end
        self:ShowFormation(config, formation1, formation2)
    else
        self:ShowFormation(config, formation1, nil)
    end

    local isFormation = config.showMode == BattleViewMode.Formation
    if isFormation then
        self._battleMgr:SetFormationRoot(config.showMode)
    else
        self._battleMgr:SetCameraMode(BattleCameraMode.Formation)
    end
    ClosePanel(UiNames.Battle)
    ClosePanel(UiNames.BattleResult)
    ClosePanel(UiNames.BattleGain)
    ClosePanel(UiNames.BattleStatistics)
    ShowPanel(UiNames.Formation, {battleConfig = config})
end

---@param formation1 LxFormationObj
---@param formation2 LxFormationObj
function LxBattleCtrl:ShowFormation(config, formation1, formation2)
    if config then
        local battleType = config.battleType
        local isFormationMode = config.showMode == BattleViewMode.Formation
        if not isFormationMode then
            if config.monsterRefId then
                formation2 = formation2 or config.formation2
                if not formation2 then
                    formation2 = ModuleCenter.Battle:GetMonsterFormation(config.monsterRefId)
                    formation2.formationType = battleType
                end
                config.formation2 = formation2
            else
                if not formation2 then
                    formation2 = config.formation2
                end
            end
        end

        if config.isTestBattle then
            config.formation1 = formation1
            config.formation2 = formation2
            if formation2 then
                ---@type LxFormationObj
                local newFormation2 = ModuleCenter.Battle:NewFormation()
                newFormation2.order = formation2.order
                newFormation2.power = formation2.power
                newFormation2.formationRefId = formation2.formationRefId
                newFormation2.count = formation2.count
                for i, v in pairs(formation2.positions) do
                    ---@type LxHeroObj
                    local heroObj = ModuleCenter.Hero:GetHero(v.id)
                    local heroPosObj = newFormation2:AddHeroPos(v.index, heroObj)
                    heroPosObj.id = tostring(i)
                end
                formation2 = newFormation2
            end
        end

        if not formation1 then
            formation1 = ModuleCenter.Battle:NewFormation()
            ModuleCenter.Battle:AddFormation(battleType, formation1, config.defend)
        end
    end

    if MgrCenter.LevelMgr:IsInLevel(LevelNames.Battle) then
        if formation1 then
            local heroMod = ModuleCenter.Hero
            local notExistHeroList = {}
            for i, v in pairs(formation1.positions) do
                if v:IsHero() then
                    ---@type LxHeroObj
                    local heroObj = heroMod:GetHero(v.id)
                    if heroObj then
                        v.heroRefId = heroObj.refId
                        v.level = heroObj.level
                    else
                        if LOG_INFO_ENABLED then
                            LogError("LxBattleCtrl:ShowFormation not exist! id="..v.id)
                        end
                        table.insert(notExistHeroList, v.index)
                    end
                end
            end
            for i, v in ipairs(notExistHeroList) do
                formation1:AddHeroPos(v, nil)
            end
        end
        self._battleMgr:ShowFormation(config, formation1, formation2)
    end
end

function LxBattleCtrl:ChangeFormationId(config, battleType, formationIdx, toId, bSave, isDefend)
    local bSetSuccess = ModuleCenter.Battle:ChangeFormationId(battleType, formationIdx, toId, isDefend)
    if not bSetSuccess then
        return false
    end
    if battleType ~= BattleType.Test then
        if bSave then
            self:SaveFormation(battleType)
        else
            self._isNeedSaveFormation = true
        end
    end

    local formationObj =  ModuleCenter.Battle:GetFormation(battleType, formationIdx, isDefend)
    if formationObj then
        self:ShowFormation(config, formationObj)
    end
    return true
end


function LxBattleCtrl:SetFormationHero(config, battleType, formationIdx, posIdx, heroObj, bSave, isDefend)
    local bSetSuccess = ModuleCenter.Battle:SetFormationHero(battleType, formationIdx, posIdx, heroObj, isDefend)
    if not bSetSuccess then
        ShowSysMsg(I18nText(2007))
        return false
    end

    if battleType ~= BattleType.Test then
        if bSave then
            self:SaveFormation(battleType)
        else
            self._isNeedSaveFormation = true
        end
    end
    if battleType == BattleType.Test  then
        local formationObj1 =  ModuleCenter.Battle:GetFormation(battleType, 1)
        local formationObj2 =  ModuleCenter.Battle:GetFormation(battleType, 1, true)
        self:ShowFormation(config, formationObj1, formationObj2)
    else
        local formationObj =  ModuleCenter.Battle:GetFormation(battleType, formationIdx, isDefend)
        if formationObj then
            self:ShowFormation(config, formationObj)
        end
    end
    return true
end

function LxBattleCtrl:IsNeedSaveFormation()
    return self._isNeedSaveFormation
end

function LxBattleCtrl:SetNeedSaveFormation(bNeed)
    self._isNeedSaveFormation = bNeed
end

function LxBattleCtrl:SaveFormation(battleType,formationReqIndex)
    self._isNeedSaveFormation = false

    local formationGroup = ModuleCenter.Battle:GetFormationList(battleType)
    local formationDefendGroup = ModuleCenter.Battle:GetFormationList(battleType, true)
    if #formationGroup == 0  and #formationDefendGroup == 0 then
        ShowSysMsg(I18nText(2009))
    else
        if #formationGroup == 0 then
            local obj = ModuleCenter.Battle:NewFormation(formationDefendGroup[1])
            obj.order = 1
            ModuleCenter.Battle:AddFormation(battleType,obj)
            table.insert(formationGroup, obj)
        end
        ---@type LxFormationObj
        local formationDefendObj = formationDefendGroup[1]
        ---@type LxFormationObj
        local formationObj = formationGroup[1]

        if not formationObj or formationObj.count == 0 and formationDefendObj then
            for i, unitPosObj in pairs(formationDefendObj.positions) do
                formationObj:AddUnit(unitPosObj)
            end
        end

        if not formationObj:HasAnyHero() then
            ShowSysMsg(I18nText(2009))
            return
        end

        ---TODO 临时把竞技场的进攻阵形设置成防守阵形，以后开了设置防守阵形的，去掉
        if battleType == BattleType.Arena then
            formationDefendGroup = {}
            local obj = ModuleCenter.Battle:NewFormation(formationGroup[1])
            obj.order = 1
            ModuleCenter.Battle:AddFormation(battleType,obj, true)
            table.insert(formationDefendGroup, obj)
        end

        HandlerCenter.Battle:SetFormationReq(battleType, formationGroup, formationDefendGroup, formationReqIndex)
    end
end

function LxBattleCtrl:OnSaveFormationFinish(battleType, reqIndex)
    local battleProcess = self._battleMgr:GetBattleProcess(battleType)
    if battleProcess then
        if not battleProcess:IsDisposed() and battleProcess:IsValid() and battleProcess.formationReqIndex == reqIndex then
            battleProcess:OnFormationFinish()
        end
    end
end

function LxBattleCtrl:OnCombatResultFinish(pb)
    local battleType = pb.combatType
    local battleProcess = self._battleMgr:GetBattleProcess(battleType)
    if battleProcess then
        if not battleProcess:IsDisposed() and battleProcess:IsValid() then
            battleProcess:OnBattleResultFinish(pb)
        end
    end
end


function LxBattleCtrl:OnReqCombatFinish(pb)
    if not self._isLoginAfter and not self._isCheckOfflineBattle then
        --离线战斗处理
        table.insert(ModuleCenter.Battle.offlineBattlePbDataList, pb)
        return
    end
    local battleType = pb.combatType
    local battleProcess = self._battleMgr:GetBattleProcess(battleType)
    if battleProcess then
        if not battleProcess:IsDisposed() and battleProcess:IsValid() then
            battleProcess:OnReqCombatFinish(pb)
        end
    end
end

function LxBattleCtrl:OnCombatReportCreateFinish(battleType, id, size)
    local battleProcess = self._battleMgr:GetBattleProcess(battleType)
    if battleProcess then
        if not battleProcess:IsDisposed() and battleProcess:IsValid() then
            battleProcess:OnBattleReportCreateFinish(id)
        end
    end
end

---离线战斗处理
function LxBattleCtrl:CheckCacheOfflineBattle()
    self._isCheckOfflineBattle = true
    local offlineBattlePbDataList = ModuleCenter.Battle.offlineBattlePbDataList
    if not offlineBattlePbDataList or #offlineBattlePbDataList == 0 then
        return
    end
    ModuleCenter.Battle.offlineBattlePbDataList = {}
    for k, pb in ipairs(offlineBattlePbDataList) do
        local battleType = pb.combatType
        local process = self._battleMgr:AddBattleProcess(battleType)
        if process then
            process:StartOfflineBattle(pb)
        end
    end
end

-- 打开战斗
---@param config V_Battle_BattleConfig
function LxBattleCtrl:OpenBattle(config, isNeedSaveFormation)
    self._curUIMode = BattleViewMode.Battle

    local isOpenWithoutView = config.isOpenWithoutView

    config.isFormation = false
    config.defend = false
    config.showMode = BattleViewMode.Battle

    local battleType = config.battleType or 1

    local battleProcess = self._battleMgr:GetBattleProcess(battleType)
    if battleProcess then
        if battleProcess:IsDisposed() or battleProcess:IsCanReplace() then
            self._battleMgr:RemoveBattleProcess(battleProcess)
            battleProcess = nil
        end
    end

    if not battleProcess then
        battleProcess = self._battleMgr:AddBattleProcess(battleType)
        battleProcess:SetBattleConfig(config)
    end

    if not battleProcess:CheckCanStartProcess() then
        ShowSysMsg(I18nText(2078))
        return
    end

    CtrlCenter.Game:RemovePopPanelByParams(UiNames.BattleResult, "battleType", battleType)

    if not battleProcess:StartProcessBattle(isNeedSaveFormation) then
        return
    end

    if not isOpenWithoutView then
        self._battleMgr:SetCameraMode(BattleCameraMode.Battle)
        ClosePanel(UiNames.Formation)
        ShowPanel(UiNames.Battle, {battleConfig = config})
        ShowPanel(UiNames.MainBottom)
    end
end


---@return LFightReportData
function LxBattleCtrl:GetBattleReportData(httpPbData)
    local reportData = require("LApp.gameplay.battle.data.LFightReportData"):new()
    reportData:InitData(httpPbData)
    return reportData
end

function LxBattleCtrl:OpenBattleStatistics(httpPbData, config)
    local reportData = self:GetBattleReportData(httpPbData)
    ShowPanel(UiNames.BattleStatistics, {
        isFromHttp = true,
        bBackFormation = config and config.bBackFormation,
        reportData = reportData,
        battleConfig = config
    })
end

function LxBattleCtrl:GotoBattleStatistics(serverId , reportId, callBack)
    self:StartReportGetter(serverId, reportId, callBack)
end

function LxBattleCtrl:StartTextAssetReportGetter(assetName, callback, reportData)
    self._battleMgr:AddTextAssetReportGetter(assetName, callback, reportData)
end

function LxBattleCtrl:StartReportGetter(serverId , reportId, callback, reportData)
    if not serverId or serverId <= 0 then
        serverId = ModuleCenter.Login:GetLoginServerId() or ""
    end
    self._battleMgr:AddReportGetter(serverId, reportId, callback, reportData)
end


---@param reportData LFightReportData
function LxBattleCtrl:ShowBattle(config, reportData, isOpenWithoutView)
    if not reportData or reportData:IsDisposed() then return end
    local bShowView = MgrCenter.LevelMgr:IsInLevel(LevelNames.Battle)
    if isOpenWithoutView then
        bShowView = false
    end
    local reportId = reportData.id
    self._battleMgr:AddBattle(reportId, reportData, bShowView, config)
    if not bShowView then
        if self._battleMgr:HasAnyLiveBattle() then
            --ShowPanel(UiNames.BattleBubble)
        end
    end
end

---@param reportData LFightReportData 战斗操作
function LxBattleCtrl:OnBattleOps(reportData)
    if not reportData or reportData:IsDisposed() then
        return
    end
    local reportId = reportData.id
    self._battleMgr:OnBattleOps(reportId)
end

--- 战斗倍数
function LxBattleCtrl:GetCombatSpeedList()
    local list = self._combatSpeedList
    if not list then
        list = {}
        local ref = GameTable.CombatSpeedRef
        for k,v in pairs(ref) do
            table.insert(list,v)
        end
        table.sort(list,function(a, b) return a.refId < b.refId end)
        self._combatSpeedList = list
    end
    return list
end

--- 编辑器保存的spine技能路径
function LxBattleCtrl:GetSpineSkillSavePath(dataName)
    local strList = string.split(dataName, "_")
    if #strList == 3 then
        local fileNames = {}
        for i = 1,#strList - 1 do
            table.insert(fileNames, strList[i])
        end
        local fileNameStr = table.concat(fileNames, "_")
        return "Spine/" .. fileNameStr
    end
    return nil
end


function LxBattleCtrl:SetGMSpeed(speed)
    ModuleCenter.Battle.GM_Speed = speed
end

function LxBattleCtrl:GetGMSpeed()
    return  ModuleCenter.Battle.GM_Speed
end

function LxBattleCtrl:GetBattleMgr()
    return self._battleMgr
end

function LxBattleCtrl:IsHaveAnyBattleShow()
    return self._battleMgr and self._battleMgr:IsAnyBattleShow() or false
end

function LxBattleCtrl:IsBattleInBackground(battleType)
    return self._battleMgr and self._battleMgr:IsBattleInBackground(battleType) or false
end

function LxBattleCtrl:IsHasBattle(battleType)
    if not self._battleMgr then
        return false
    end
    local battleProcess = self._battleMgr:GetBattleProcess(battleType)
    if not battleProcess then
        return false
    end
    local isLive = not battleProcess:IsDisposed() and not battleProcess:IsCanReplace()
    return isLive
end

function LxBattleCtrl:IsCanSkip(battleType, showTips)
    --特权

    --战斗本身条件
    local combatTypeRef = GameTable.CombatTypeRef[battleType]
    if not combatTypeRef then
        return true
    end
    if combatTypeRef.canSkip == 0 then
        return false
    end
    local conditions = combatTypeRef.skipCondition
    local isValid = true
    if conditions then
        isValid = CtrlCenter.FuncOpen:CheckConditions(conditions)
    end
    return isValid
end

---@param battleReport LFightReportData
function LxBattleCtrl:AddBattleNotice(battleReport)
    local battleType = battleReport.battleType
    self:RemoveBattleNotice(battleType)
    table.insert(ModuleCenter.Battle.battleNoticeList, {report = battleReport})
    ShowPanel(UiNames.BattleNoticePop)
end

function LxBattleCtrl:RemoveBattleNotice(battleType, bFireEvent)
    local noticeList = ModuleCenter.Battle.battleNoticeList
    local isChange = false
    for k,v in ipairs(noticeList) do
        if v.report.battleType == battleType then
            if not v.remove then
                isChange = true
                v.remove = true
            end
        end
    end
    if isChange and bFireEvent then
        FireEvent(EventNames.BATTLE_NOTICE_REMOVE)
    end
end

---援军数据获取
function LxBattleCtrl:GetReliefTroopData(battleType, battleConfig)
    local reliefTroop = nil
    if battleType == BattleType.Adventure then
        local refId = battleConfig and battleConfig.refId or 0
        local instanceRef = GameTable.InsMissionRef[refId]
        if instanceRef then
            reliefTroop = instanceRef.reliefTroop
        end
    elseif battleType == BattleType.CityMonster then
        local refId = battleConfig and battleConfig.refId or 0
        local cityMonsterRef = GameTable.CityMonsterRef[refId]
        if cityMonsterRef then
            reliefTroop = cityMonsterRef.reliefTroop
        end
    else
        reliefTroop = battleConfig.reliefTroop
    end

    if not reliefTroop or reliefTroop <= 0 then
        return false, nil
    end
    local ref = GameTable.BattleReliefTroopRef[reliefTroop]
    if ref then
        local confirmTroop = ref.confirmTroop or {}
        local confirmTroopList = {}
        for k,v in ipairs(confirmTroop) do
            local params = string.split(v,"=")
            local param1 = tonumber(params[1]) or 0
            local param2 = tonumber(params[2]) or 0
            local param3 = tonumber(params[3]) or 0
            table.insert(confirmTroopList,{param1, param2, param3})
        end

        local freeTroopList = ref.freeTroop or {}

        local heroReplace = ref.heroReplace
        local heroReplaceList = {}
        for k,v in ipairs(heroReplace) do
            local params = string.split(v,"=")
            local param1 = tonumber(params[1]) or 0
            local param2 = tonumber(params[2]) or 0
            local param3 = tonumber(params[3]) or 0
            local param4 = tonumber(params[4]) or 0
            table.insert(heroReplaceList,{param1, param2, param3, param4})
        end


        local formation = ref.formation

        local monList = {}
        local heroList = {}
        local fixedIndex = {}
        local fixedInFormation = {}
        local monRefId = 0
        local gridIndex = 0
        local refIdRecord = {}

        local monMap = {}
        local monToHeroRefId = {}
        local matrixT = ModuleCenter.Battle:GetFormationIndexGridMatrixT()
        local matrix = matrixT[formation] or {}
        local gridToIndex = matrix.gridToIndex or {}
        local monPowerMap = {}

        for k, v in ipairs(confirmTroopList) do
            monRefId = v[3]
            gridIndex = v[1]
            local index = gridToIndex[gridIndex] or 1
            local isFixed = (v[2] == 0)
            local monsterRef = GameTable.MonsterAttrRef[monRefId]
            if monsterRef then
                local race = monsterRef.raceType
                table.insert(monList, { refId = monRefId, index = index, pos = gridIndex, isFixed = isFixed, race = race , power = monsterRef.monsterPower})
                fixedInFormation[monRefId] = true
                if isFixed then
                    fixedIndex[gridIndex] = index
                end
                monMap[monRefId] = true
                monToHeroRefId[monRefId] = monsterRef.heroId
                monPowerMap[tostring(monRefId)] = monsterRef.monsterPower
            end
        end

        local heroRefId = 0
        for k, v in ipairs(heroReplaceList) do
            heroRefId = v[3]
            monRefId = v[4]
            gridIndex = v[1]
            local heroObj = ModuleCenter.Hero:GetMaxPowerHeroByRefId(heroRefId)
            local isFixed = (v[2] == 0)
            local index = gridToIndex[gridIndex] or 1
            if  heroObj then
                local race = LxDataHelper.GetHeroRaceType(heroRefId)
                table.insert(heroList, { id = heroObj.id, heroObj = heroObj, refId = heroRefId, index = index, pos = gridIndex, isFixed = isFixed, race = race})
                fixedInFormation[heroObj.id] = true
                refIdRecord[heroRefId] = true
                if isFixed then
                    fixedIndex[gridIndex] = index
                end
            else
                local monsterRef = GameTable.MonsterAttrRef[monRefId]
                if monsterRef then
                    local race = monsterRef.raceType
                    table.insert(monList, { refId = monRefId, index = index, pos = gridIndex, isFixed = isFixed, race = race, power = monsterRef.monsterPower})
                    fixedInFormation[monRefId] = true

                    if isFixed then
                        fixedIndex[gridIndex] = index
                    end
                    monMap[monRefId] = true
                    monToHeroRefId[monRefId] = monsterRef.heroId
                    monPowerMap[tostring(monRefId)] = monsterRef.monsterPower
                end
            end
        end

        local tmpFreeList = {}
        for k, v in ipairs(freeTroopList) do
            monRefId = v
            local monsterRef = GameTable.MonsterAttrRef[monRefId]
            local race = monsterRef.raceType
            table.insert(tmpFreeList, { refId = monRefId, grid = 0, isFixed = false, race = race , power = monsterRef.monsterPower})
            monMap[monRefId] = true
            monToHeroRefId[monRefId] = monsterRef.heroId
            monPowerMap[tostring(monRefId)] = monsterRef.monsterPower
        end

        local dataTbl = {
            refIdRecord = {},
            refId = reliefTroop,
            cfg = ref,
            formation = formation,
            freeTroopList = tmpFreeList,
            selfHero = ref.selfHero == 1,
            monList = monList,
            heroList = heroList,
            fixedIndex = fixedIndex,
            fixedInFormation = fixedInFormation,
            monMap = monMap,
            monToHeroRefId = monToHeroRefId,
            monPowerMap = monPowerMap,
        }
        return true, dataTbl
    end
end

return LxBattleCtrl